import React from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link } from "react-router-dom";

function FormComponent({ info, handleBtn, params }) {
  function resestForm() {
    document.getElementById("front").value = "";
    document.getElementById("back").value = "";
  }

  return (
    <div>
      <Form>
        <Col>
          <h1>{info.name ? info.name : null} Add Card</h1>
          <Form.Label className="mt-1">Front</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Front of card"
            as="textarea"
            id="front"
          ></Form.Control>
          <Form.Label className="mt-1">Back</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Back of card"
            as="textarea"
            id="back"
          ></Form.Control>
          <Link to={`/decks/${params.deckId}`}>
            <Button className="mt-2 mr-1" variant="secondary">
              Done
            </Button>
          </Link>
          <Link to={`/decks/${params.deckId}`}>
            <Button onClick={() => {handleBtn(); resestForm();}} className="mt-2 mr-1">
              Save
            </Button>
          </Link>
        </Col>
      </Form>
    </div>
  );
}

export default FormComponent;
